To achieve one index cache per index file, you can modify your code to store the index cache in the same directory as the index file. This way, when you remove the index file, you can also remove the associated index cache.

Here's a basic example of how you can implement this in Python:

```python
import os
import pickle

class IndexCache:
    def __init__(self, index_file):
        self.index_file = index_file
        self.cache_dir = os.path.dirname(index_file)
        self.cache_file = os.path.join(self.cache_dir, 'index_cache.pkl')

    def load_cache(self):
        if os.path.exists(self.cache_file):
            with open(self.cache_file, 'rb') as f:
                return pickle.load(f)
        return {}

    def save_cache(self, cache):
        with open(self.cache_file, 'wb') as f:
            pickle.dump(cache, f)

    def get(self):
        return self.load_cache()

    def set(self, cache):
        self.save_cache(cache)

    def delete(self):
        try:
            os.remove(self.cache_file)
        except FileNotFoundError:
            pass
```

