import { createContext, useContext, useState } from 'react';
import { notify } from '../helpers/notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const NotificationContext = createContext(null);

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [notification, setNotification] = useState<NotificationProps | null>(null);

  const triggerNotification = async (props: NotificationProps) => {
    if (!notificationElem) return;

    try {
      await notify(notificationElem, props);
      setNotification(props);
    } catch (error) {
      console.error(error);
    }
  };

  return { triggerNotification, notification };
};

